  // 获取地区排行榜 - 集成缓存优化
  static async getRegionLeaderboard(req, res) {
    try {
      const { period = 'daily', limit = 50, offset = 0 } = req.query;

      // 构建缓存键
      const cacheKey = `leaderboard:region:${period}:${limit}:${offset}`;

      // 先从缓存获取
      let leaderboard = await CacheService.getLeaderboard('region', period);
      
      if (!leaderboard) {
        // 从数据库获取
        const timeFilter = this.getTimeFilter(period);
        
        const query = db('regions')
          .select(
            'regions.id',
            'regions.name',
            'regions.flag',
            'regions.color',
            db.raw('COUNT(DISTINCT pixels.user_id) as user_count'),
            db.raw('COUNT(DISTINCT alliances.id) as alliance_count'),
            db.raw('COUNT(pixels.id) as total_pixels')
          )
          .leftJoin(
            db.raw(`
              pixels ON ST_DWithin(
                ST_SetSRID(ST_MakePoint(pixels.lng, pixels.lat), 4326),
                ST_SetSRID(ST_MakePoint(regions.center_lng, regions.center_lat), 4326),
                regions.radius
              )
            `)
          )
          .leftJoin('alliance_members', 'pixels.user_id', 'alliance_members.user_id')
          .leftJoin('alliances', 'alliance_members.alliance_id', 'alliances.id')
          .where('regions.is_active', true)
          .groupBy('regions.id', 'regions.name', 'regions.flag', 'regions.color')
          .orderBy('total_pixels', 'desc')
          .limit(parseInt(limit))
          .offset(parseInt(offset));

        if (timeFilter) {
          query.where('pixels.created_at', '>=', timeFilter);
        }

        const results = await query;

        leaderboard = {
          period,
          data: results,
          pagination: {
            limit: parseInt(limit),
            offset: parseInt(offset)
          }
        };

        // 缓存结果
        await CacheService.setLeaderboard('region', period, leaderboard);
      }

      res.json({
        success: true,
        data: leaderboard
      });
    } catch (error) {
      console.error('获取地区排行榜失败:', error);
      res.status(500).json({
        success: false,
        message: '获取地区排行榜失败',
        error: error.message
      });
    }
  }

  // 获取用户排名 - 集成缓存优化
  static async getUserRank(req, res) {
    try {
      const { userId } = req.params;
      const { period = 'daily' } = req.query;

      // 构建缓存键
      const cacheKey = `user_rank:${userId}:${period}`;

      // 先从缓存获取
      let rankInfo = await CacheService.get(cacheKey);
      
      if (!rankInfo) {
        // 从数据库获取
        const timeFilter = this.getTimeFilter(period);
        
        const query = db('pixels')
          .select(
            'users.id',
            'users.username',
            'users.display_name',
            db.raw('COUNT(pixels.id) as pixel_count')
          )
          .join('users', 'pixels.user_id', 'users.id')
          .where('users.is_active', true)
          .groupBy('users.id', 'users.username', 'users.display_name')
          .orderBy('pixel_count', 'desc');

        if (timeFilter) {
          query.where('pixels.created_at', '>=', timeFilter);
        }

        const allUsers = await query;
        
        const userIndex = allUsers.findIndex(user => user.id === userId);
        const userRank = userIndex >= 0 ? userIndex + 1 : null;
        const userData = allUsers[userIndex] || null;

        rankInfo = {
          period,
          rank: userRank,
          user: userData,
          total_users: allUsers.length
        };

        // 缓存结果（短期缓存）
        await CacheService.set(cacheKey, rankInfo, 300); // 5分钟缓存
      }

      res.json({
        success: true,
        data: rankInfo
      });
    } catch (error) {
      console.error('获取用户排名失败:', error);
      res.status(500).json({
        success: false,
        message: '获取用户排名失败',
        error: error.message
      });
    }
  }

